sql:
SELECT point_id, access_date
FROM access_logs
WHERE user_id = 2 AND access_date BETWEEN '2023-01-01 00:00:00' AND '2023-01-31 23:59:59';

SELECT COUNT(*)
FROM data_point_anomalies
WHERE anomaly_score > (SELECT AVG(anomaly_score) FROM data_point_anomalies);

SELECT point_id
FROM data_point_anomalies
WHERE anomaly_score > 0.8;

SELECT anomaly_id
FROM data_point_anomalies
WHERE anomaly_score > 0.90;

SELECT point_id, x, y, label_id
FROM data_points
WHERE version = (
    SELECT MAX(version) 
    FROM data_points
);

SELECT COUNT(*) 
FROM data_point_anomalies 
WHERE user_id = 1;

SELECT anomaly_id, anomaly_score
FROM data_point_anomalies
WHERE algorithm = 'Local Outlier Factor';

SELECT trend_label, algorithm, trend_description
FROM data_point_trends
LIMIT 1;

SELECT anomaly_description
FROM data_point_anomalies
WHERE point_id = 0;

SELECT label_name 
FROM labels 
WHERE label_id IN (SELECT label_id FROM data_points);

SELECT TANH(trend_id) AS TrendHyperbolicTangent
FROM data_point_trends
WHERE trend_label = 'Decreasing Trend';

SELECT dp.point_id, dp.x, dp.y, dp.number_points, dp.version, dp.created_at, dp.updated_at, dp.time_series, dp.data_type, dp.metadata, dp.status
FROM data_points dp
INNER JOIN data_point_trends dt ON dp.point_id = dt.point_id;

SELECT COUNT(*) AS num_data_points
FROM data_points
WHERE data_type = 'spatial';

SELECT COUNT(DISTINCT c.point_id) AS total_points_with_clusters_and_trends
FROM data_point_clusters c
INNER JOIN data_point_trends t ON c.point_id = t.point_id;

